// Sliding dovetail joint — a tail beam and a socket beam that slide together.
// A classic woodworking joint translated to FDM; the clearance keeps the fit
// snug but printable. Good for joining flat panels without screws.
const { Manifold, printFit } = api;

const beamW = 30, beamD = 20, beamL = 80;

// Dovetail geometry (normal fit for sliding assembly).
const { tail, socket: dtSocket } = printFit.dovetail({
  length: beamL,
  width: 14,
  depth: 8,
  angle: 15,
  fit: 'normal',
});

// ---- Tail beam: rectangular beam with the dovetail tail proud on the top face.
// The tail runs along +X; base the beam on the XY plane.
const tailBeam = Manifold.cube([beamL, beamW, beamD], false);
// Union the tail on top of the beam (it rises from z=beamD, embedded 0.5 into face).
const tailFull = tailBeam.add(
  tail.translate([0, beamW/2, beamD - 0.5]),
);

// ---- Socket beam: same footprint but with the dovetail channel cut in.
const socketBeam = Manifold.cube([beamL, beamW, beamD], false);
const socketFull = socketBeam.subtract(
  dtSocket.translate([0, beamW/2, beamD]),
);

// Lay out side by side (socket beside tail, separated by 15 mm).
return tailFull.add(socketFull.translate([0, beamW + 15, 0]));
